## Step 2: Implement Per-CWD Command Registry in ClaudeCodeRuntime

### File: `apps/server/src/services/runtimes/claude-code/claude-code-runtime.ts`

Replace the single `commandRegistry` field with a Map-based cache:

```typescript
// Before
private commandRegistry: CommandRegistryService | null = null;

async getCommands(forceRefresh?: boolean): Promise<CommandRegistry> {
  if (!this.commandRegistry) {
    this.commandRegistry = new CommandRegistryService(this.cwd);
  }
  return this.commandRegistry.getCommands(forceRefresh);
}

// After
private commandRegistries = new Map<string, CommandRegistryService>();
private static readonly MAX_COMMAND_REGISTRIES = 50;

async getCommands(forceRefresh?: boolean, cwd?: string): Promise<CommandRegistry> {
  const root = cwd || this.cwd;
  let registry = this.commandRegistries.get(root);
  if (!registry) {
    // Evict oldest entry if cache is full
    if (this.commandRegistries.size >= ClaudeCodeRuntime.MAX_COMMAND_REGISTRIES) {
      const oldest = this.commandRegistries.keys().next().value!;
      this.commandRegistries.delete(oldest);
    }
    registry = new CommandRegistryService(root);
    this.commandRegistries.set(root, registry);
  }
  return registry.getCommands(forceRefresh);
}
```

This moves the LRU cache from the route into the runtime, preserving the same behavior and size limit.

## Step 3: Simplify the Route

### File: `apps/server/src/routes/commands.ts`

Replace the entire file with:
```typescript
import { Router } from 'express';
import { runtimeRegistry } from '../services/core/runtime-registry.js';
import { CommandsQuerySchema } from '@dorkos/shared/schemas';
import { validateBoundary, BoundaryError } from '../lib/boundary.js';

const router = Router();

// GET /api/commands - List all commands (with optional refresh and cwd)
router.get('/', async (req, res) => {
  const parsed = CommandsQuerySchema.safeParse(req.query);
  if (!parsed.success) {
    return res.status(400).json({ error: 'Invalid query', details: parsed.error.format() });
  }
  const refresh = parsed.data.refresh === 'true';
  try {
    let validatedCwd: string | undefined;
    if (parsed.data.cwd) {
      validatedCwd = await validateBoundary(parsed.data.cwd);
    }
    const runtime = runtimeRegistry.getDefault();
    const commands = await runtime.getCommands(refresh, validatedCwd);
    res.json(commands);
  } catch (err) {
    if (err instanceof BoundaryError) {
      return res.status(403).json({ error: err.message, code: err.code });
    }
    throw err;
  }
});

export default router;
```

